#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int Ns[100]; // T <= 100 as per constraints
    int maxN = 0;
    for (int i = 0; i < T; ++i) {
        scanf("%d", &Ns[i]);
        if (Ns[i] > maxN) maxN = Ns[i];
    }
    if (maxN < 2) maxN = 2;
    bool *isPrime = (bool *)malloc((maxN + 1) * sizeof(bool));
    for (int i = 0; i <= maxN; ++i) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i <= maxN; ++i) {
        if (isPrime[i]) {
            for (int j = i * i; j <= maxN; j += i) isPrime[j] = false;
        }
    }
    for (int i = 0; i < T; ++i) {
        int N = Ns[i];
        int ok = 0;
        for (int p = 2; p <= N / 2; ++p) {
            if (isPrime[p] && isPrime[N - p]) { ok = 1; break; }
        }
        printf("%s\n", ok ? "YES" : "NO");
    }
    free(isPrime);
    return 0;
}

